import ldap

def search_user_by_username(ldap_server, base_dn, username):
    try:
        # Connect to the LDAP server
        l = ldap.initialize(ldap_server)
        l.simple_bind_s()

        # Define the search filter and attributes
        search_filter = f"uid={username}"
        search_attributes = ["cn", "mail"]

        # Perform the search
        result_id = l.search(base_dn, ldap.SCOPE_SUBTREE, search_filter, search_attributes)

        # Get the results
        results = []
        while 1:
            type, data = l.result(result_id, 0)
            if not data:
                break
            for entry in data:
                results.append(entry[1])

        return results

    except ldap.LDAPError as e:
        print(f"LDAP error: {e}")
        return None

